(function(){
  function bankQ(arr, tag, color, bg){ const e = pick(arr); return mkQ(e.q, e.a, shuffle([...e.o]), e.h, tag, color, bg); }
  BTH.plants = `<h3>Растения и их органы</h3><div class="fm">Корень закрепляет растение и всасывает воду<br>Стебель держит листья и проводит вещества<br>Лист образует питательные вещества на свету<br>Цветок нужен для размножения<br>Семя даёт новое растение</div><p>Для фотосинтеза нужны свет, вода и углекислый газ.</p>`;
  GTH.atm = `<h3>Атмосфера и погода</h3><div class="fm">Атмосфера — воздушная оболочка Земли<br>В ней образуются облака, ветер и осадки<br>Барометр показывает давление<br>Термометр показывает температуру</div><p>Без атмосферы на Земле не было бы воздуха и привычной погоды.</p>`;
  function genPlants6(){
    return bankQ([
      {q:'Какой орган растения всасывает воду из почвы?', a:'корень', o:['корень','цветок','лист','плод'], h:'Корни находятся в земле.'},
      {q:'Где у растения образуются питательные вещества на свету?', a:'в листьях', o:['в листьях','в корне','в семени','в плоде'], h:'Листья участвуют в фотосинтезе.'},
      {q:'Как называется процесс образования питательных веществ на свету?', a:'фотосинтез', o:['фотосинтез','испарение','опыление','дыхание'], h:'Для него нужен свет.'},
      {q:'Что помогает растению удерживаться в почве?', a:'корень', o:['корень','лист','цветок','плод'], h:'Он не только питает, но и закрепляет растение.'},
      {q:'Для чего растению нужен цветок?', a:'для размножения', o:['для размножения','для дыхания','для роста корня','для удержания воды'], h:'После цветка могут образоваться плод и семя.'},
      {q:'Что обычно образуется из семени?', a:'новое растение', o:['новое растение','только корень','только лист','камень'], h:'Семя прорастает.'},
      {q:'Что проводит воду и вещества от корня к листьям?', a:'стебель', o:['стебель','цветок','плод','семя'], h:'Стебель соединяет части растения.'},
      {q:'Что нужно растению для фотосинтеза?', a:'свет, вода и воздух', o:['свет, вода и воздух','только темнота','только снег','только камни'], h:'Без света листья не смогут работать.'}
    ], 'Растения и их органы', '#16a34a', '#dcfce7');
  }
  function genAtm6(){
    return bankQ([
      {q:'Как называется воздушная оболочка Земли?', a:'атмосфера', o:['атмосфера','литосфера','гидросфера','магма'], h:'Она окружает Землю.'},
      {q:'Что измеряет барометр?', a:'атмосферное давление', o:['атмосферное давление','температуру','скорость ветра','высоту гор'], h:'Барометр связан с давлением воздуха.'},
      {q:'Что измеряет термометр?', a:'температуру', o:['температуру','влажность почвы','давление','время'], h:'Температуру воздуха и воды.'},
      {q:'Дождь и снег — это:', a:'осадки', o:['осадки','течение','магма','горы'], h:'Они выпадают из облаков.'},
      {q:'Почему на Земле есть ветер?', a:'воздух перемещается из-за разницы температур и давления', o:['воздух перемещается из-за разницы температур и давления','Земля перестаёт вращаться','только из-за дождя','только ночью'], h:'Тёплый и холодный воздух движутся по-разному.'},
      {q:'Где образуются облака?', a:'в атмосфере', o:['в атмосфере','в ядре Земли','в океанском дне','в почве'], h:'Облака состоят из капелек воды и льдинок.'},
      {q:'Что защищает Землю от многих метеоритов и резких перепадов температуры?', a:'атмосфера', o:['атмосфера','песок','почва','реки'], h:'Атмосфера — важная защита планеты.'},
      {q:'Что сильнее влияет на погоду сегодня: климат или состояние атмосферы сейчас?', a:'состояние атмосферы сейчас', o:['состояние атмосферы сейчас','только карта','только океан','только лес'], h:'Погода — это то, что происходит сейчас.'}
    ], 'Атмосфера и погода', '#2563eb', '#dbeafe');
  }
  const bio = SUBJ.find(s => s.id === 'bio');
  const geo = SUBJ.find(s => s.id === 'geo6');
  if(bio && !bio.tops.find(t => t.id === 'plants')) bio.tops.push({id:'plants', nm:'Растения и их органы', gen:genPlants6, th:BTH.plants, dot:'#16a34a'});
  if(geo && !geo.tops.find(t => t.id === 'atm')) geo.tops.push({id:'atm', nm:'Атмосфера и погода', gen:genAtm6, th:GTH.atm, dot:'#2563eb'});
})();
